        'from datetime import datetime',
        'from datetime import datetime\nfrom dateutil import parser as dateutil_parser'
    )

# Replace parse_timestamp function
old_parse = '''def parse_timestamp(ts: Optional[str]) -> Optional[datetime]:
    """Parse ISO timestamp string to datetime.

    Handles timezone suffixes and returns naive datetime for comparison.
    """
    if not ts:
        return None
    try:
        ts = ts.replace('Z', '+00:00')
        if '+' in ts:
            ts = ts.split('+')[0]
        return datetime.fromisoformat(ts)
    except (ValueError, TypeError, AttributeError) as e:
        # Log warning but don't fail - return None for invalid timestamps
        trace_log("reconciliation", "parse_timestamp_error", {
            "timestamp": ts,
            "error": str(e)
        })
        return None'''

new_parse = '''def parse_timestamp(ts: Optional[str]) -> Optional[datetime]:
    """Parse ISO timestamp string to datetime using dateutil.

    Handles various timestamp formats and timezones, returns naive datetime for comparison.
    """
    if not ts:
        return None
    try:
        # dateutil.parser handles ISO8601, RFC3339, and many other formats
        dt = dateutil_parser.parse(ts)
        # Convert to naive datetime (strip timezone for comparison)
        return dt.replace(tzinfo=None) if dt.tzinfo else dt
    except (ValueError, TypeError, AttributeError) as e:
        # Log warning but don't fail - return None for invalid timestamps
        trace_log("reconciliation", "parse_timestamp_error", {
            "timestamp": ts,
            "error": str(e)
        })
        return None'''

content = content.replace(old_parse, new_parse)

with open('src/services/reconciliation.py', 'w') as f:
    f.write(content)
print("✓ Updated timestamp parsing to use python-dateutil")
