echo "[Phase 3.3] Improving string matching logic to avoid false positives..."

# Fix 7: Improve substring matching with length checks
python3 << 'PYTHON_EOF'
with open('src/services/reconciliation.py', 'r') as f:
    lines = f.readlines()

output = []
for i, line in enumerate(lines):
    # Fix cloud resource substring matching (around line 228)
    if 'if any(n in name or name in n for n in normalized_names):' in line:
        indent = len(line) - len(line.lstrip())
        output.append(' ' * indent + '# Substring match with length check to avoid false positives (e.g., "aws" matching "awsome")\n')
        output.append(' ' * indent + 'if any((len(n) > 3 and len(name) > 3 and (n in name or name in n)) for n in normalized_names):\n')
        continue

    # Fix vendor substring matching in contracts (around line 245)
    if 'if vendor in key or key in vendor:' in line and 'for key in name_to_keys.keys():' in lines[i-1]:
        indent = len(line) - len(line.lstrip())
        output.append(' ' * indent + '# Substring match with length check\n')
        output.append(' ' * indent + 'if len(vendor) > 3 and len(key) > 3 and (vendor in key or key in vendor):\n')
        continue

    # Fix product substring matching (around line 252)
    if 'if product in key or key in product:' in line and 'for key in name_to_keys.keys():' in lines[i-1]:
        indent = len(line) - len(line.lstrip())
        output.append(' ' * indent + '# Substring match with length check\n')
        output.append(' ' * indent + 'if len(product) > 3 and len(key) > 3 and (product in key or key in product):\n')
        continue

    # Fix transaction vendor substring matching (around line 269)
    if 'if vendor in key or key in vendor:' in line and 'for key in name_to_keys.keys():' in lines[i-2:i]:
        indent = len(line) - len(line.lstrip())
        output.append(' ' * indent + '# Substring match with length check\n')
        output.append(' ' * indent + 'if len(vendor) > 3 and len(key) > 3 and (vendor in key or key in vendor):\n')
        continue

    output.append(line)

with open('src/services/reconciliation.py', 'w') as f:
    f.writelines(output)
print("✓ Improved substring matching with length checks")
PYTHON_EOF

